      setDoc(null);
      setRawEdi('');
      setOriginalEdi('');
      setRecords([]);
      setSelectedRecordId(null);
      setSelectedSegment(null);

      setFormData(INITIAL_FORM_DATA);
      setFormData276({} as any);
      setFormData837({} as any);
      setFormData834(INITIAL_FORM_DATA_834);
      setFormData278({} as any);
      setFormData820({} as any);
